const body = $input.first().json.body || {};
const message = (body.message || '').trim();
const session_id = (body.session_id || 'pe-default').trim();

// Health-check: отдаём pong без вызова LLM
if (message === 'ping') {
  return [{ json: { valid: 0, error: 'pong' } }];
}

if (!message || message.length < 2) {
  return [{ json: { valid: 0, error: 'Введите сообщение' } }];
}

if (message.length > 10000) {
  return [{ json: { valid: 0, error: 'Слишком длинный запрос (максимум 10000 символов)' } }];
}

return [{ json: { valid: 1, message: message, session_id: session_id } }];

const message = $('Агрегация').first().json.message;
const historyContext = $('Агрегация').first().json.historyContext || '';
const lower = message.toLowerCase();

const promptKeywords = [
  'промпт', 'prompt', 'системн', 'создай', 'напиши', 'сгенерируй',
  'адаптируй', 'адаптировать', 'переделай', 'переделать', 'перепиши под',
  'переписать под', 'измени под', 'изменить под', 'подстрой', 'подстроить',
  'улучши', 'улучшить', 'доработай', 'доработать', 'оптимизируй',
  'оптимизировать', 'исправь промпт', 'усиль', 'усилить', 'сделай лучше',
  'что не так с промптом', 'проанализируй промпт',
  'инструкци', 'для модели', 'для нейросет', 'для ии', 'для ai',
  'для gigachat', 'для гигачат', 'для бота', 'для чат-бота',
  'роль ассистент', 'ты —', 'you are'
];

const hasExistingPrompt = (
  (message.includes('```') || message.includes('Ты —') || message.includes('Ты -') || message.includes('You are')) &&
  message.length > 100
);

let isPromptTask = hasExistingPrompt;
if (!isPromptTask) {
  for (const kw of promptKeywords) {
    if (lower.includes(kw)) { isPromptTask = true; break; }
  }
}

if (!isPromptTask && message.length > 50) {
  const taskIndicators = ['нужен', 'нужно', 'хочу', 'сделай', 'помоги написать', 'составь', 'разработай'];
  for (const kw of taskIndicators) {
    if (lower.includes(kw)) { isPromptTask = true; break; }
  }
}

if (!isPromptTask) {
  return [{ json: { message, mode: 'general', modeLabel: 'Общение', historyContext } }];
}

const adaptKeywords = ['адаптируй', 'адаптировать', 'переделай', 'переделать', 'перепиши под', 'переписать под', 'измени под', 'изменить под', 'подстрой', 'подстроить'];
const improveKeywords = ['улучши', 'улучшить', 'доработай', 'доработать', 'оптимизируй', 'оптимизировать', 'исправь промпт', 'усиль', 'усилить', 'сделай лучше', 'что не так с промптом', 'проанализируй промпт'];

let mode = 'create';
let modeLabel = 'Создание нового промпта';

for (const kw of adaptKeywords) {
  if (lower.includes(kw)) { mode = 'adapt'; modeLabel = 'Адаптация промпта'; break; }
}

if (mode === 'create') {
  for (const kw of improveKeywords) {
    if (lower.includes(kw)) { mode = 'improve'; modeLabel = 'Улучшение промпта'; break; }
  }
}

if (mode === 'create' && hasExistingPrompt) {
  mode = 'improve';
  modeLabel = 'Улучшение промпта';
}

return [{ json: { message, mode, modeLabel, historyContext } }];

try {
  const raw = $input.first().json;
  if (raw.error) {
    return [{ json: { response: 'Не удалось обработать запрос. Попробуйте ещё раз.', prompt: '' } }];
  }
  const text = raw.output[0].content[0].text;
  return [{ json: { response: text.trim(), prompt: '' } }];
} catch(e) {
  return [{ json: { response: 'Ошибка обработки.', prompt: '' } }];
}

try {
  const raw = $input.first().json;

  if (raw.error) {
    return [{ json: { response: 'GigaChat недоступен. Попробуйте позже.', prompt: '' } }];
  }

  const generatedText = raw.output[0].content[0].text;

  let extractedPrompt = '';
  const codeMatch = generatedText.match(/```[\s\S]*?\n([\s\S]*?)```/);
  if (codeMatch) {
    extractedPrompt = codeMatch[1].trim();
  }

  return [{ json: { response: generatedText, prompt: extractedPrompt } }];
} catch(e) {
  return [{ json: { response: 'Ошибка обработки ответа GigaChat: ' + e.message, prompt: '' } }];
}

const historyRows = $input.all().reverse();
let historyContext = '';
if (historyRows.length > 0) {
  const lines = historyRows.map(item => {
    const role = item.json.role === 'user' ? 'Пользователь' : 'Ассистент';
    return role + ': ' + (item.json.content || '');
  });
  historyContext = 'История диалога:\n' + lines.join('\n') + '\n\n';
}
const v = $('Валидация').first().json;
return [{json: {message: v.message, session_id: v.session_id, historyContext: historyContext}}];
